"use client";

import { useEffect, useState } from "react";
import { TrendingUp, ShoppingBag, DollarSign, Users, AlertCircle, CheckCircle2 } from "lucide-react";
import Link from "next/link";

interface DashboardMetrics {
  totalOrders: number;
  totalRevenue: number;
  pendingOrders: number;
  completedOrders: number;
  cancelledOrders: number;
  lowStockProducts: number;
  recentOrders: Array<{
    id: string;
    customer_name: string;
    total: number;
    status: string;
    created_at: string;
  }>;
}

export default function AdminDashboard() {
  const [metrics, setMetrics] = useState<DashboardMetrics | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetch("/api/admin/metrics")
      .then((res) => {
        if (!res.ok) throw new Error("Failed to load metrics");
        return res.json();
      })
      .then((data) => {
        setMetrics(data);
        setLoading(false);
      })
      .catch((err) => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-emerald-600 mx-auto" />
          <p className="mt-4 text-gray-600">Cargando métricas...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <AlertCircle className="h-12 w-12 text-red-600 mx-auto mb-4" />
          <p className="text-gray-600">Error: {error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Dashboard</h1>
            <p className="text-gray-600 mt-1">Resumen general de la tienda</p>
          </div>
          <div className="flex gap-3">
            <Link
              href="/panel-privado/orders"
              className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50"
            >
              Pedidos
            </Link>
            <Link
              href="/panel-privado/inventory"
              className="px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50"
            >
              Inventario
            </Link>
          </div>
        </div>

        {/* Métricas Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <MetricCard
            icon={DollarSign}
            label="Ingresos Totales"
            value={`$${metrics?.totalRevenue.toLocaleString()}`}
            trend="Total acumulado"
            color="emerald"
          />
          <MetricCard
            icon={ShoppingBag}
            label="Pedidos Totales"
            value={metrics?.totalOrders.toString() || "0"}
            trend="Todos los estados"
            color="indigo"
          />
          <MetricCard
            icon={CheckCircle2}
            label="Pedidos Completados"
            value={metrics?.completedOrders.toString() || "0"}
            trend="Entregados exitosamente"
            color="green"
          />
          <MetricCard
            icon={AlertCircle}
            label="Pedidos Pendientes"
            value={metrics?.pendingOrders.toString() || "0"}
            trend="Requieren atención"
            color="amber"
          />
        </div>

        {/* Alertas de Inventario */}
        {metrics && metrics.lowStockProducts > 0 && (
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-8">
            <div className="flex items-center gap-3">
              <AlertCircle className="h-5 w-5 text-amber-600" />
              <div>
                <p className="text-sm font-semibold text-amber-800">
                  Productos con stock bajo
                </p>
                <p className="text-sm text-amber-700">
                  {metrics.lowStockProducts} productos tienen 5 o menos unidades disponibles
                </p>
              </div>
              <Link
                href="/panel-privado/inventory"
                className="ml-auto px-3 py-1.5 bg-amber-100 text-amber-800 text-sm font-medium rounded-md hover:bg-amber-200"
              >
                Ver inventario
              </Link>
            </div>
          </div>
        )}

        {/* Pedidos Recientes */}
        <div className="bg-white rounded-lg shadow">
          <div className="flex items-center justify-between p-6 border-b">
            <h2 className="text-xl font-semibold text-gray-900">Pedidos Recientes</h2>
            <Link
              href="/panel-privado/orders"
              className="text-sm font-medium text-emerald-600 hover:text-emerald-700"
            >
              Ver todos →
            </Link>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    ID
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Cliente
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Total
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Estado
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                    Fecha
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {metrics?.recentOrders.map((order) => (
                  <tr key={order.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 text-sm text-gray-900 font-mono">
                      {order.id.slice(0, 8)}...
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-900">
                      {order.customer_name || "N/A"}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-900 font-medium">
                      ${order.total.toLocaleString()}
                    </td>
                    <td className="px-6 py-4">
                      <StatusBadge status={order.status} />
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500">
                      {new Date(order.created_at).toLocaleDateString("es-CO", {
                        year: "numeric",
                        month: "short",
                        day: "numeric",
                      })}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

function MetricCard({
  icon: Icon,
  label,
  value,
  trend,
  color = "emerald",
}: {
  icon: any;
  label: string;
  value: string;
  trend: string;
  color?: string;
}) {
  const colors: Record<string, string> = {
    emerald: "bg-emerald-50 text-emerald-600",
    indigo: "bg-indigo-50 text-indigo-600",
    green: "bg-green-50 text-green-600",
    amber: "bg-amber-50 text-amber-600",
    red: "bg-red-50 text-red-600",
  };

  return (
    <div className="bg-white rounded-lg shadow p-6">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm text-gray-600">{label}</p>
          <p className="text-2xl font-bold text-gray-900 mt-1">{value}</p>
          <p className="text-sm text-gray-500 mt-2">{trend}</p>
        </div>
        <div className={`flex h-12 w-12 items-center justify-center rounded-xl ${colors[color]}`}>
          <Icon className="h-6 w-6" />
        </div>
      </div>
    </div>
  );
}

function StatusBadge({ status }: { status: string }) {
  const colors: Record<string, string> = {
    pending: "bg-yellow-100 text-yellow-800",
    processing: "bg-blue-100 text-blue-800",
    shipped: "bg-purple-100 text-purple-800",
    delivered: "bg-green-100 text-green-800",
    cancelled: "bg-red-100 text-red-800",
    refunded: "bg-gray-100 text-gray-800",
  };

  const labels: Record<string, string> = {
    pending: "Pendiente",
    processing: "Procesando",
    shipped: "Enviado",
    delivered: "Entregado",
    cancelled: "Cancelado",
    refunded: "Reembolsado",
  };

  return (
    <span className={`px-2.5 py-1 rounded-full text-xs font-medium ${colors[status] || "bg-gray-100 text-gray-800"}`}>
      {labels[status] || status}
    </span>
  );
}

﻿"use client";

import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { X, MessageCircle } from "lucide-react";
import { cn } from "@/lib/utils";
import { WHATSAPP_PHONE } from "@/lib/site";
import { useLanguage } from "@/providers/LanguageProvider";

export function ExitIntentPopup() {
  const [show, setShow] = useState(false);
  const [dismissed, setDismissed] = useState(false);
  const { t } = useLanguage();
  const waUrl = useMemo(() => {
    const message = encodeURIComponent(t("exitIntent.message"));
    return `https://wa.me/${WHATSAPP_PHONE}?text=${message}`;
  }, [t]);

  const handleMouseLeave = useCallback(
    (e: MouseEvent) => {
      if (dismissed) return;
      if (e.clientY <= 5 && e.relatedTarget === null) {
        if (document.querySelector('[role="dialog"][aria-modal="true"]')) {
          return;
        }
        setShow(true);
      }
    },
    [dismissed]
  );

  useEffect(() => {
    const mq = window.matchMedia("(pointer: fine)");
    if (!mq.matches) return;

    try {
      if (sessionStorage.getItem("vortixy_exit_dismissed")) return;
    } catch {
      // ignore
    }

    const timer = setTimeout(() => {
      document.addEventListener("mouseout", handleMouseLeave);
    }, 5000);

    return () => {
      clearTimeout(timer);
      document.removeEventListener("mouseout", handleMouseLeave);
    };
  }, [handleMouseLeave]);

  const dismiss = useCallback(() => {
    setShow(false);
    setDismissed(true);
    try {
      sessionStorage.setItem("vortixy_exit_dismissed", "1");
    } catch {
      // ignore
    }
  }, []);

  const openAssistant = useCallback(() => {
    dismiss();
    window.dispatchEvent(new CustomEvent("vortixy:assistant-open"));
  }, [dismiss]);

  useEffect(() => {
    if (!show) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") dismiss();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [show, dismiss]);

  // Focus trap for accessibility
  useEffect(() => {
    if (!show) return;

    const modal = document.querySelector('[role="dialog"]');
    if (!modal) return;

    const focusableElements = modal.querySelectorAll<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    const firstElement = focusableElements[0];
    const lastElement = focusableElements[focusableElements.length - 1];

    const handleTabKey = (e: KeyboardEvent) => {
      if (e.key !== "Tab") return;

      if (e.shiftKey && document.activeElement === firstElement) {
        e.preventDefault();
        lastElement.focus();
      } else if (!e.shiftKey && document.activeElement === lastElement) {
        e.preventDefault();
        firstElement.focus();
      }
    };

    document.addEventListener("keydown", handleTabKey);
    firstElement.focus();

    return () => document.removeEventListener("keydown", handleTabKey);
  }, [show]);

  if (!show) return null;

  return (
    <div
      className="fixed inset-0 z-[70] flex items-center justify-center p-4"
      role="dialog"
      aria-modal="true"
      aria-label={t("exitIntent.ariaLabel")}
    >
      <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={dismiss} />

      <div className="surface-panel-dark surface-ambient brand-v-slash relative w-full max-w-sm overflow-hidden rounded-3xl border border-white/10 text-white shadow-[var(--shadow-float-strong)] animate-[fade-in-up_300ms_ease-out]">
        <div className="relative z-[1] flex items-center justify-between border-b border-white/10 px-5 pb-4 pt-5 sm:px-6">
          <div>
            <p className="text-[10px] font-semibold uppercase tracking-[0.18em] text-emerald-200/78">
              Ayuda inmediata
            </p>
            <p className="mt-1 text-sm text-white/60">
              Soporte rapido antes de salir
            </p>
          </div>
          <button
            onClick={dismiss}
            aria-label={t("common.close")}
            className="inline-flex h-10 w-10 items-center justify-center rounded-full border border-white/10 bg-white/8 text-white/72 transition-all hover:bg-white/15 hover:text-white"
          >
            <X className="h-4 w-4" />
          </button>
        </div>

        <div className="px-6 pb-6 pt-6 text-center">
          <div className="relative mx-auto mb-5 flex h-16 w-16 items-center justify-center rounded-full border border-[#25D366]/25 bg-[#25D366]/15 shadow-lg shadow-[#25D366]/10">
            <MessageCircle className="w-8 h-8 text-[#25D366]" />
          </div>

          <h3 className="mb-2 text-xl font-bold text-white">
            {t("exitIntent.title")}
          </h3>
          <p className="mb-6 text-sm leading-relaxed text-white/68">
            {t("exitIntent.subtitle")}
          </p>

          <button
            onClick={openAssistant}
            className={cn(
              "flex items-center justify-center gap-2.5 w-full",
              "h-12 rounded-2xl",
              "bg-gradient-to-r from-[#25D366] to-emerald-500 text-white text-sm font-semibold",
              "shadow-[var(--shadow-whatsapp-soft)]",
              "hover:from-[#20BD5A] hover:to-emerald-600 active:scale-[0.98] transition-all duration-300"
            )}
          >
            <MessageCircle className="w-5 h-5" />
            {t("assistant.open")}
          </button>

          <a
            href={waUrl}
            target="_blank"
            rel="noopener noreferrer"
            onClick={dismiss}
            className="mt-3 inline-flex items-center justify-center gap-2 text-xs font-medium text-white/58 transition-colors hover:text-white/80"
          >
            <MessageCircle className="h-4 w-4" />
            {t("assistant.handoffButton")}
          </a>

          <button
            onClick={dismiss}
            className="mt-4 text-xs text-white/45 transition-colors hover:text-white/70"
          >
            {t("exitIntent.dismiss")}
          </button>
        </div>
      </div>
    </div>
  );
}

